rule-obj-activity.pageList:
{% for param in parameters | default([]) %}

  {{ param.name }}
  {{ param.type | default('Text') }}
  {{ param.mode | default('In') }}

{% endfor %}

{% for step in steps | default([]) %}

  {{ loop.index }}
  {{ step.method }}
  {% if step.method == "Property-Set" %}
  {{ step.target_property }}
  {{ step.value }}
  {% endif %}
  {% if step.method == "Call" %}
  {{ step.call_class | default(pega_class) }}
  {{ step.call_activity }}
  {% endif %}
  {% if step.method == "Obj-Open" or step.method == "Obj-Save" %}
  {{ step.page }}
  {{ step.obj_class | default(pega_class) }}
  {% endif %}
  {% if step.method == "Connect-REST" or step.method == "Connect-SOAP" %}
  {{ step.connector_class }}
  {{ step.connector_name }}
  {% endif %}
  {{ step.label | default('') }}
  {{ step.condition | default('') }}

{% endfor %}
